const rows = $input.all();
const messages = rows.map((item, index) => {
  const msg = item.json || {};
  const from = msg.from || msg.sender || {};
  const fromEmail = typeof from === 'string' ? from : (from.email || from.address || msg.from_email || msg.sender_email || 'unknown@example.invalid');
  const fromName = typeof from === 'string' ? '' : (from.name || from.displayName || msg.from_name || msg.sender_name || '');
  return {
    id: String(msg.id || msg.messageId || msg.message_id || `n8n-local-${index}`),
    threadId: String(msg.threadId || msg.thread_id || msg.conversationId || msg.conversation_id || ''),
    from: {
      email: String(fromEmail),
      name: String(fromName)
    },
    subject: String(msg.subject || ''),
    snippet: String(msg.snippet || msg.preview || msg.bodyPreview || msg.text || '').slice(0, 1200),
    receivedAt: String(msg.receivedAt || msg.received_at || msg.date || msg.timestamp || new Date().toISOString()),
    provider: String(msg.provider || 'n8n'),
    source: {
      workflow: 'botfucker-local-review-import',
      node: 'Normalize BotFucker Payload'
    }
  };
});
return [{ json: { messages } }];
